query:
-- Remove duplicate leads (keep only the first occurrence of each email)
DELETE FROM leads WHERE id NOT IN (
  SELECT MIN(id) FROM leads GROUP BY email
) AND email IS NOT NULL;

-- Remove leads with no email and duplicate names (keep first)
DELETE FROM leads WHERE id NOT IN (
  SELECT MIN(id) FROM leads GROUP BY firstName, lastName, COALESCE(email, CONCAT(id,'_unique'))
);

-- Remove duplicate campaigns (keep first per name)
DELETE FROM campaigns WHERE id NOT IN (
  SELECT MIN(id) FROM campaigns GROUP BY name
);

-- Remove duplicate templates (keep first per name+channel)
DELETE FROM templates WHERE id NOT IN (
  SELECT MIN(id) FROM templates GROUP BY name, channel
);

-- Remove duplicate onboardings (keep first per clientName)
DELETE FROM onboardings WHERE id NOT IN (
  SELECT MIN(id) FROM onboardings GROUP BY clientName
);

-- Remove duplicate testimonials (keep first per clientName)
DELETE FROM testimonials WHERE id NOT IN (
  SELECT MIN(id) FROM testimonials GROUP BY clientName
);

-- Remove duplicate call_recordings (keep first per leadId+calledAt)
DELETE FROM call_recordings WHERE id NOT IN (
  SELECT MIN(id) FROM call_recordings GROUP BY leadId, calledAt
);

